/// <summary>
/// Lightweight value cascaded app-wide via CascadingValueSource so the
/// static layout can read it through a [CascadingParameter].
/// </summary>
public class WizardProgress
{
    public int CurrentStep { get; init; }
    public int TotalSteps { get; init; } = 4;
    public HashSet<int> CompletedSteps { get; init; } = [];
}

namespace sv_897558d22a334c799386fd24d88b46e4.Services;

/// <summary>
/// Scoped service that holds all wizard form data for a single user's circuit.
/// Each circuit gets its own instance, so users never share data.
/// </summary>
public class ApplicationState
{
    // Step 1 — Personal Info
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;

    // Step 2 — Experience
    public List<JobHistoryEntry> JobHistory { get; set; } = [];

    // Step 3 — References
    public List<ReferenceContact> References { get; set; } = [];

    // Track which steps have been saved
    public HashSet<int> CompletedSteps { get; } = [];

    public void MarkCompleted(int step) => CompletedSteps.Add(step);
}

public class JobHistoryEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Years { get; set; } = string.Empty;
}

