@page "/apply/personal-info"
@rendermode InteractiveServer
@inject ApplicationState AppState
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Personal Info — Step 1</PageTitle>

<h1>Personal Information</h1>

<EditForm Model="this" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="AppState.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="AppState.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    protected override async Task OnInitializedAsync()
    {
        await ProgressSource.NotifyChangedAsync(
            new WizardProgress { CurrentStep = 1, CompletedSteps = AppState.CompletedSteps });
    }

    private async Task Next()
    {
        AppState.MarkCompleted(1);
        await ProgressSource.NotifyChangedAsync(
            new WizardProgress { CurrentStep = 1, CompletedSteps = AppState.CompletedSteps });
        Nav.NavigateTo("apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@inject ApplicationState AppState
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Experience — Step 2</PageTitle>

<h1>Work Experience</h1>

@for (var i = 0; i < AppState.JobHistory.Count; i++)
{
    var index = i;
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between">
            <strong>Entry @(index + 1)</strong>
            <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveEntry(index)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="AppState.JobHistory[index].Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Job Title</label>
            <input class="form-control" @bind="AppState.JobHistory[index].Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="AppState.JobHistory[index].Years" />
        </div>
    </div>
}

<button type="button" class="btn btn-outline-primary mb-3" @onclick="AddEntry">+ Add Entry</button>

<div class="d-flex gap-2">
    <button type="button" class="btn btn-secondary" @onclick="Back">← Back</button>
    <button type="button" class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    protected override async Task OnInitializedAsync()
    {
        if (AppState.JobHistory.Count == 0)
            AppState.JobHistory.Add(new());

        await ProgressSource.NotifyChangedAsync(
            new WizardProgress { CurrentStep = 2, CompletedSteps = AppState.CompletedSteps });
    }

    private void AddEntry() => AppState.JobHistory.Add(new());

    private void RemoveEntry(int index)
    {
        if (AppState.JobHistory.Count > 1)
            AppState.JobHistory.RemoveAt(index);
    }

    private void Back() => Nav.NavigateTo("apply/personal-info");

    private async Task Next()
    {
        AppState.MarkCompleted(2);
        await ProgressSource.NotifyChangedAsync(
            new WizardProgress { CurrentStep = 2, CompletedSteps = AppState.CompletedSteps });
        Nav.NavigateTo("apply/references");
    }
}

@page "/apply/references"
@rendermode InteractiveServer
@inject ApplicationState AppState
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>References — Step 3</PageTitle>

<h1>References</h1>

@for (var i = 0; i < AppState.References.Count; i++)
{
    var index = i;
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between">
            <strong>Reference @(index + 1)</strong>
            <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveRef(index)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Name</label>
            <input class="form-control" @bind="AppState.References[index].Name" />
        </div>
        <div class="mb-2">
            <label class="form-label">Email</label>
            <input class="form-control" @bind="AppState.References[index].Email" />
        </div>
        <div class="mb-2">
            <label class="form-label">Relationship</label>
            <input class="form-control" @bind="AppState.References[index].Relationship" />
        </div>
    </div>
}

<button type="button" class="btn btn-outline-primary mb-3" @onclick="AddRef">+ Add Reference</button>

<div class="d-flex gap-2">
    <button type="button" class="btn btn-secondary" @onclick="Back">← Back</button>
    <button type="button" class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    protected override async Task OnInitializedAsync()
    {
        if (AppState.References.Count == 0)
            AppState.References.Add(new());

        await ProgressSource.NotifyChangedAsync(
            new WizardProgress { CurrentStep = 3, CompletedSteps = AppState.CompletedSteps });
    }

    private void AddRef() => AppState.References.Add(new());

    private void RemoveRef(int index)
    {
        if (AppState.References.Count > 1)
            AppState.References.RemoveAt(index);
    }

    private void Back() => Nav.NavigateTo("apply/experience");

    private async Task Next()
    {
        AppState.MarkCompleted(3);
        await ProgressSource.NotifyChangedAsync(
            new WizardProgress { CurrentStep = 3, CompletedSteps = AppState.CompletedSteps });
        Nav.NavigateTo("apply/review");
    }
}

@page "/apply/review"
@rendermode InteractiveServer
@inject ApplicationState AppState
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Review — Step 4</PageTitle>

<h1>Review Your Application</h1>

<div class="card mb-3 p-3">
    <h5>Personal Information</h5>
    <dl class="row mb-0">
        <dt class="col-sm-3">Name</dt>
        <dd class="col-sm-9">@AppState.Name</dd>
        <dt class="col-sm-3">Email</dt>
        <dd class="col-sm-9">@AppState.Email</dd>
    </dl>
</div>

<div class="card mb-3 p-3">
    <h5>Work Experience</h5>
    @if (AppState.JobHistory.Count == 0)
    {
        <p class="text-muted">No entries added.</p>
    }
    else
    {
        <ul class="list-group list-group-flush">
            @foreach (var job in AppState.JobHistory)
            {
                <li class="list-group-item">
                    <strong>@job.Title</strong> at @job.Company — @job.Years
                </li>
            }
        </ul>
    }
</div>

