﻿@inherits LayoutComponentBase

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (Progress is not null && Progress.CurrentStep > 0)
            {
                <nav aria-label="Application progress" class="d-flex align-items-center gap-3 w-100">
                    <span class="fw-semibold">Step @Progress.CurrentStep of @Progress.TotalSteps</span>
                    <div class="progress flex-grow-1" style="height: 8px;">
                        <div class="progress-bar"
                             role="progressbar"
                             style="width: @((int)(Progress.CurrentStep * 100.0 / Progress.TotalSteps))%"
                             aria-valuenow="@Progress.CurrentStep"
                             aria-valuemin="0"
                             aria-valuemax="@Progress.TotalSteps">
                        </div>
                    </div>
                    @foreach (var step in Enumerable.Range(1, Progress.TotalSteps))
                    {
                        var label = step switch { 1 => "Personal Info", 2 => "Experience", 3 => "References", _ => "Review" };
                        var href = step switch { 1 => "apply/personal-info", 2 => "apply/experience", 3 => "apply/references", _ => "apply/review" };
                        var css = step == Progress.CurrentStep
                            ? "btn btn-primary btn-sm"
                            : Progress.CompletedSteps.Contains(step)
                                ? "btn btn-success btn-sm"
                                : "btn btn-outline-secondary btn-sm";
                        <a href="@href" class="@css">@label</a>
                    }
                </nav>
            }
            else
            {
                <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
            }
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    [CascadingParameter]
    private WizardProgress? Progress { get; set; }
}

